	private void OnSearchBarTextChanged(LineEditEventArgs args)
	{
		List<WantedRecord> records = ((!string.IsNullOrWhiteSpace(args.Text)) ? _wantedRecords.FindAll((WantedRecord r) => r.TargetInfo.Name.Contains(args.Text) || r.Status.ToString().Contains(args.Text, StringComparison.OrdinalIgnoreCase)) : _wantedRecords);
		UpdateState(records, refresh: false);
	}

	public void UpdateState(List<WantedRecord> records, bool refresh = true)
	{
		if (records.Count == 0)
		{
			((Control)NoRecords).Visible = true;
			((Control)RecordsList).Visible = false;
			((Control)RecordUnselected).Visible = false;
			((Control)PersonContainer).Visible = false;
			_selectedTargetName = null;
			if (refresh)
			{
				_wantedRecords.Clear();
			}
			RecordsList.PopulateList(new List<ListData>());
			return;
		}
		((Control)NoRecords).Visible = false;
		((Control)RecordsList).Visible = true;
		((Control)RecordUnselected).Visible = true;
		((Control)PersonContainer).Visible = false;
		List<StatusListData> data = records.Select((WantedRecord r) => new StatusListData(r)).ToList();
		RecordsList.GenerateItem = GenerateItem;
		RecordsList.ItemPressed = OnItemSelected;
		RecordsList.PopulateList(data);
		if (refresh)
		{
			_wantedRecords = records;
		}
	}

